const WebSocket = require('ws');
const crypto = require('crypto');

const wss = new WebSocket.Server({ port: 8080 });

const games = new Map();
const players = new Map();

class Game {
  constructor(gameId) {
    this.gameId = gameId;
    this.players = new Map();
    this.units = new Map();
    this.buildings = new Map();
    this.commandHistory = new Map();
    this.nonces = new Map();
  }

  addPlayer(playerId, ws) {
    this.players.set(playerId, {
      ws,
      resources: 1000,
      units: new Set(),
      buildings: new Set()
    });
    this.commandHistory.set(playerId, new Map());
    this.nonces.set(playerId, new Set());
  }

  removePlayer(playerId) {
    this.players.delete(playerId);
    this.commandHistory.delete(playerId);
    this.nonces.delete(playerId);
  }

  validateCommand(playerId, command) {
    if (!command.nonce || !command.timestamp) {
      return { valid: false, error: 'Missing nonce or timestamp' };
    }

    const playerNonces = this.nonces.get(playerId);
    if (playerNonces.has(command.nonce)) {
      return { valid: false, error: 'Nonce already used (replay attack detected)' };
    }

    const currentTime = Date.now();
    const commandTime = command.timestamp;
    const timeDiff = Math.abs(currentTime - commandTime);
    
    if (timeDiff > 30000) {
      return { valid: false, error: 'Command timestamp too old or too far in future' };
    }

    const playerHistory = this.commandHistory.get(playerId);
    const commandKey = `${command.type}_${command.nonce}`;
    
    if (playerHistory.has(commandKey)) {
      return { valid: false, error: 'Duplicate command detected' };
    }

    return { valid: true };
  }

  recordCommand(playerId, command) {
    const playerNonces = this.nonces.get(playerId);
    playerNonces.add(command.nonce);

    const playerHistory = this.commandHistory.get(playerId);
    const commandKey = `${command.type}_${command.nonce}`;
    playerHistory.set(commandKey, {
      timestamp: command.timestamp,
      recordedAt: Date.now()
    });

    this.cleanupOldCommands(playerId);
  }

  cleanupOldCommands(playerId) {
    const playerHistory = this.commandHistory.get(playerId);
    const playerNonces = this.nonces.get(playerId);
    const currentTime = Date.now();
    const maxAge = 60000;

    for (const [key, data] of playerHistory.entries()) {
      if (currentTime - data.recordedAt > maxAge) {
        playerHistory.delete(key);
      }
    }

    if (playerNonces.size > 10000) {
      const noncesArray = Array.from(playerNonces);
      const toKeep = noncesArray.slice(-5000);
      this.nonces.set(playerId, new Set(toKeep));
    }
  }

  processCommand(playerId, command) {
    const validation = this.validateCommand(playerId, command);
    if (!validation.valid) {
      return { success: false, error: validation.error };
    }

    this.recordCommand(playerId, command);

    const player = this.players.get(playerId);
    if (!player) {
      return { success: false, error: 'Player not found' };
    }

    switch (command.type) {
      case 'build':
        return this.handleBuild(playerId, command);
      case 'attack':
        return this.handleAttack(playerId, command);
      case 'move':
        return this.handleMove(playerId, command);
      default:
        return { success: false, error: 'Unknown command type' };
    }
  }

  handleBuild(playerId, command) {
    const player = this.players.get(playerId);
    const buildingCost = 100;

    if (player.resources < buildingCost) {
      return { success: false, error: 'Insufficient resources' };
    }

    player.resources -= buildingCost;
    const buildingId = crypto.randomBytes(16).toString('hex');
    
    this.buildings.set(buildingId, {
      id: buildingId,
      owner: playerId,
      type: command.buildingType || 'barracks',
      position: command.position || { x: 0, y: 0 },
      health: 100
    });

    player.buildings.add(buildingId);

    this.broadcast({
      type: 'buildingCreated',
      buildingId,
      owner: playerId,
      buildingType: command.buildingType || 'barracks',
      position: command.position || { x: 0, y: 0 }
    });

    return { success: true, buildingId };
  }

  handleAttack(playerId, command) {
    const player = this.players.get(playerId);
    
    if (!command.unitId || !command.targetId) {
      return { success: false, error: 'Missing unitId or targetId' };
    }

    const unit = this.units.get(command.unitId);
    if (!unit || unit.owner !== playerId) {
      return { success: false, error: 'Unit not found or not owned by player' };
    }

    const target = this.units.get(command.targetId) || this.buildings.get(command.targetId);
    if (!target) {
      return { success: false, error: 'Target not found' };
    }

    const damage = 10;
    target.health -= damage;

    this.broadcast({
      type: 'attack',
      attacker: command.unitId,
      target: command.targetId,
      damage,
      targetHealth: target.health
    });

    if (target.health <= 0) {
      this.units.delete(command.targetId);
      this.buildings.delete(command.targetId);
      this.broadcast({
        type: 'entityDestroyed',
        entityId: command.targetId
      });
    }

    return { success: true };
  }

  handleMove(playerId, command) {
    const player = this.players.get(playerId);
    
    if (!command.unitId || !command.destination) {
      return { success: false, error: 'Missing unitId or destination' };
    }

    const unit = this.units.get(command.unitId);
    if (!unit || unit.owner !== playerId) {
      return { success: false, error: 'Unit not found or not owned by player' };
    }

    unit.position = command.destination;

    this.broadcast({
      type: 'unitMoved',
      unitId: command.unitId,
      position: command.destination
    });

    return { success: true };
  }

  broadcast(message) {
    const data = JSON.stringify(message);
    for (const [playerId, player] of this.players.entries()) {
      if (player.ws.readyState === WebSocket.OPEN) {
        player.ws.send(data);
      }
    }
  }
}

wss.on('connection', (ws) => {
  const playerId = crypto.randomBytes(16).toString('hex');
  let currentGame = null;

  ws.send(JSON.stringify({
    type: 'connected',
    playerId
  }));

  ws.on('message', (message) => {
    try {
      const data = JSON.parse(message);

      if (data.type === 'joinGame') {
        const gameId = data.gameId || 'default';
        
        if (!games.has(gameId)) {
          games.set(gameId, new Game(gameId));
        }

        currentGame = games.get(gameId);
        currentGame.addPlayer(playerId, ws);
        players.set(playerId, { gameId, ws });

        ws.send(JSON.stringify({
          type: 'joinedGame',
          gameId,
          playerId
        }));

        return;
      }

      if (!currentGame) {
        ws.send(JSON.stringify({
          type: 'error',
          error: 'Not in a game'
        }));
        return;
      }

      if (['build', 'attack', 'move'].includes(data.type)) {
        const result = currentGame.processCommand(playerId, data);
        ws.send(JSON.stringify({
          type: 'commandResult',
          command: data.type,
          result
        }));
      }

    } catch (error) {
      ws.send(JSON.stringify({
        type: 'error',
        error: 'Invalid message format'
      }));
    }
  });

  ws.on('close', () => {
    if (currentGame) {
      currentGame.removePlayer(playerId);
      
      if (currentGame.players.size === 0) {
        games.delete(currentGame.gameId);
      }
    }
    players.delete(playerId);
  });
});

